import{_ as l,o as a,c as i,ae as o}from"./chunks/framework.jfJLTIcL.js";const p=JSON.parse('{"title":"Release 本地验收与 TDD 规范","description":"","frontmatter":{},"headers":[],"relativePath":"zh-CN/release-tdd.md","filePath":"zh-CN/release-tdd.md","lastUpdated":1775316762000}'),t={name:"zh-CN/release-tdd.md"};function d(r,e,s,c,n,h){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="release-本地验收与-tdd-规范" tabindex="-1">Release 本地验收与 TDD 规范 <a class="header-anchor" href="#release-本地验收与-tdd-规范" aria-label="Permalink to &quot;Release 本地验收与 TDD 规范&quot;">​</a></h1><p>这份文档用于约束 VILab Tauri 桌面版的发布流程，目标是避免“开发环境正常，但打包后的 Release 出问题”。</p><h2 id="基本原则" tabindex="-1">基本原则 <a class="header-anchor" href="#基本原则" aria-label="Permalink to &quot;基本原则&quot;">​</a></h2><ul><li>不要只在 <code>tauri dev</code> 里验证修复</li><li>不要先上传 GitHub Release 再让用户帮忙验收</li><li>必须先在本地构建、安装、启动并验证打包后的 Release</li><li>必须保留可以解释问题和修复结果的测试、日志和截图证据</li><li>macOS 对外发布不能只停留在“能打出 dmg”，还必须考虑签名、公证和 Gatekeeper 体验</li></ul><h2 id="版本号单一来源" tabindex="-1">版本号单一来源 <a class="header-anchor" href="#版本号单一来源" aria-label="Permalink to &quot;版本号单一来源&quot;">​</a></h2><ul><li><code>package.json</code> 是桌面端版本号的单一来源</li><li>需要升版时，先改 <code>package.json</code> 里的 <code>version</code></li><li>然后运行 <code>npm run version:sync</code></li><li>这个脚本会把版本同步到 <code>src-tauri/Cargo.toml</code>、<code>src-tauri/tauri.conf.json</code>，并更新文档里的 <code>/health</code> 响应示例版本</li></ul><p>如果只是为了发布新版本，推荐先完成版本同步，再执行后面的构建与发布命令。</p><h2 id="推荐流程" tabindex="-1">推荐流程 <a class="header-anchor" href="#推荐流程" aria-label="Permalink to &quot;推荐流程&quot;">​</a></h2><ol><li>先在本地 Release 中复现问题</li><li>先补最小失败测试，再改代码</li><li>跑针对性的前端测试、Rust 测试和 smoke 测试</li><li>重新构建 Release 包</li><li>把安装包安装到一个新的临时目录，而不是直接复用旧目录</li><li>直接启动安装后的可执行文件，检查窗口、日志、数据落盘和核心用户路径</li><li>本地确认通过后，再更新 GitHub Release</li></ol><h2 id="平台要求" tabindex="-1">平台要求 <a class="header-anchor" href="#平台要求" aria-label="Permalink to &quot;平台要求&quot;">​</a></h2><ul><li>Windows：需要保留 NSIS 或 MSI 安装包，以及 updater 相关产物</li><li>macOS：需要至少 ad-hoc 签名；对外发布推荐使用 <code>Developer ID Application</code> 证书并完成 notarization</li><li>macOS 对外发布前，必须实际验证下载后的 <code>.dmg</code> 不会被 Gatekeeper 直接拦成“已损坏”</li></ul><h2 id="tdd-分层" tabindex="-1">TDD 分层 <a class="header-anchor" href="#tdd-分层" aria-label="Permalink to &quot;TDD 分层&quot;">​</a></h2><p>不要把验证全都压在一个端到端流程上，应该分层做：</p><ul><li>前端层：补 <code>store</code>、<code>client</code>、<code>startup</code> 这类状态流转测试</li><li>Rust 层：补启动流程、资源路径、配置路由、发布态分支的回归测试</li><li>Release 层：保留 Windows smoke，用来验证安装、启动、重复启动和退出行为</li><li>macOS Release 层：验证 codesign、Gatekeeper assessment、stapler 和下载后的安装体验</li></ul><h2 id="release-常见问题清单" tabindex="-1">Release 常见问题清单 <a class="header-anchor" href="#release-常见问题清单" aria-label="Permalink to &quot;Release 常见问题清单&quot;">​</a></h2><p>Release 与开发环境不一致时，优先检查这些问题：</p><ul><li>Tauri bridge 初始化竞态</li><li>主窗口隐藏后没有正确显示</li><li>smoke 只看进程或窗口句柄，导致假阳性</li><li>WebView2 用 <code>PrintWindow</code> 截图看起来像白屏</li><li>第二个实例占用了固定端口、全局热键或单实例锁</li><li>打包后资源路径与开发环境不一致</li><li>开发版与 Release 共用同一个 <code>%APPDATA%</code> 数据目录，但 UI 同步链路有问题</li><li>macOS 包虽然能本地打开，但下载后的 <code>.dmg/.app</code> 因为没有签名或没有 notarize 被 Gatekeeper 认定为“已损坏”</li></ul><h2 id="验收要求" tabindex="-1">验收要求 <a class="header-anchor" href="#验收要求" aria-label="Permalink to &quot;验收要求&quot;">​</a></h2><p>本地 Release 验收至少要覆盖：</p><ul><li>主窗口真实可见，且尺寸正常，不能只看 <code>MainWindowHandle</code></li><li>关键页面能加载，不是空白或启动失败页</li><li>历史记录、设置、模型状态、诊断信息能正确显示</li><li>需要落盘的动作已经写入实际数据库或文件</li><li>第二次启动不会因为端口或热键冲突而崩溃</li><li>macOS 下载后的安装包可以直接通过系统安全校验，而不是依赖用户手工去掉 quarantine</li></ul><h2 id="证据要求" tabindex="-1">证据要求 <a class="header-anchor" href="#证据要求" aria-label="Permalink to &quot;证据要求&quot;">​</a></h2><p>每次修复 Release 问题，至少保留这些证据：</p><ul><li>测试命令结果</li><li>smoke 测试结果</li><li>本地安装目录</li><li>进程 ID 与窗口尺寸</li><li>打包后应用的截图</li><li>关键日志</li><li>涉及持久化时的数据库路径和记录数量</li><li>如果是 macOS，对外发布还要保留签名、公证和 stapler 校验结果</li></ul><h2 id="发布门禁" tabindex="-1">发布门禁 <a class="header-anchor" href="#发布门禁" aria-label="Permalink to &quot;发布门禁&quot;">​</a></h2><p>以下条件没有全部满足时，不要发版：</p><ul><li>失败测试已经补上并转绿</li><li>本地 smoke 通过</li><li>本地安装后的 Release 能正常打开</li><li>目标用户路径在本地 Release 中真实可用</li><li>macOS 发布包已经完成签名与 notarization，或明确标注为仅限内部/本地测试</li><li>有足够证据说明修复成立，而不是“理论上应该好了”</li></ul>',26)])])}const m=l(t,[["render",d]]);export{p as __pageData,m as default};
